16	use crate::CompilerState;
17	
18	use leo_ast::{
19	    ArrayAccess,
20	    AssignStatement,
21	    AstVisitor,
22	    DefinitionPlace,
23	    DefinitionStatement,
24	    Expression,
25	    Identifier,
26	    IntegerType,
27	    Literal,
28	    MemberAccess,
29	    Node as _,
30	    Path,
31	    Program,
32	    Statement,
33	    Stub,
34	    Type,
35	};
36	use leo_span::Symbol;
37	
38	use indexmap::IndexMap;
39	
40	/// This visitor associates a variable for each member of a composite or array that is
41	/// written to. Whenever a member of the composite or array is written to, we change the
42	/// assignment to access the variable instead. Whenever the composite or array itself
43	/// is accessed, we first rebuild the composite or array from its variables.
44	pub struct WriteTransformingVisitor<'a> {
45	    pub state: &'a mut CompilerState,
46	
47	    /// For any composite whose members are written to, a map of its field names to variables
48	    /// corresponding to the members.
49	    pub composite_members: IndexMap<Symbol, IndexMap<Symbol, Identifier>>,
50	
51	    /// For any array whose members are written to, a vec containing the variables for each index.
52	    pub array_members: IndexMap<Symbol, Vec<Identifier>>,
53	
54	    pub program: Symbol,
55	}
56	
57	impl<'a> WriteTransformingVisitor<'a> {
58	    pub fn new(state: &'a mut CompilerState, program: &Program) -> Self {
59	        let visitor = WriteTransformingVisitor {
60	            state,
61	            composite_members: Default::default(),
62	            array_members: Default::default(),
63	            program: Symbol::intern(""),
64	        };
65	
66	        // We need to do an initial pass through the AST to identify all arrays and composites that are written to.
67	        let mut wtf = WriteTransformingFiller(visitor);
68	        wtf.fill(program);
69	        wtf.0
70	    }
71	
72	    /// If `name` is a composite or array whose members are written to, make
73	    /// `DefinitionStatement`s for each of its variables that will correspond to
74	    /// the members. Note that we create them for all members; unnecessary ones
75	    /// will be removed by DCE.
76	    pub fn define_variable_members(&mut self, name: Identifier, accumulate: &mut Vec<Statement>) {
77	        // The `cloned` here and in the branch below are unfortunate but we need
78	        // to mutably borrow `self` again below.
79	        if let Some(members) = self.array_members.get(&name.name).cloned() {
80	            for (i, member) in members.iter().cloned().enumerate() {
81	                // Create a definition for each array index.
82	                let index = Literal::integer(
83	                    IntegerType::U8,
84	                    i.to_string(),
85	                    Default::default(),
86	                    self.state.node_builder.next_id(),
87	                );
88	                self.state.type_table.insert(index.id(), Type::Integer(IntegerType::U32));
89	                let access = ArrayAccess {
90	                    array: Path::from(name).to_local().into(),
91	                    index: index.into(),
92	                    span: Default::default(),
93	                    id: self.state.node_builder.next_id(),
94	                };
95	                self.state.type_table.insert(access.id(), self.state.type_table.get(&member.id()).unwrap().clone());
96	                let def = DefinitionStatement {
97	                    place: DefinitionPlace::Single(member),
98	                    type_: None,
99	                    value: access.into(),
100	                    span: Default::default(),
101	                    id: self.state.node_builder.next_id(),
102	                };
103	                accumulate.push(def.into());
104	                // And recurse - maybe its members are also written to.
105	                self.define_variable_members(member, accumulate);
106	            }
107	        } else if let Some(members) = self.composite_members.get(&name.name) {
108	            for (&field_name, &member) in members.clone().iter() {
109	                // Create a definition for each field.
110	                let access = MemberAccess {
111	                    inner: Path::from(name).to_local().into(),
112	                    name: Identifier::new(field_name, self.state.node_builder.next_id()),
113	                    span: Default::default(),
114	                    id: self.state.node_builder.next_id(),
115	                };
116	                self.state.type_table.insert(access.id(), self.state.type_table.get(&member.id()).unwrap().clone());
117	                let def = DefinitionStatement {
118	                    place: DefinitionPlace::Single(member),
119	                    type_: None,
120	                    value: access.into(),
121	                    span: Default::default(),
122	                    id: self.state.node_builder.next_id(),
123	                };
124	                accumulate.push(def.into());
125	                // And recurse - maybe its members are also written to.
126	                self.define_variable_members(member, accumulate);
127	            }
128	        }
129	    }
130	
131	    /// If we're assigning to a composite or array member, find the variable name we're actually writing to,
132	    /// recursively if necessary.
133	    /// That is, if we have
134	    /// `arr[0u32][1u32] = ...`,
135	    /// we find the corresponding variable `arr_0_1`.
136	    pub fn reconstruct_assign_place(&mut self, input: Expression) -> Identifier {
137	        use Expression::*;
138	        match input {
139	            ArrayAccess(array_access) => {
140	                let identifier = self.reconstruct_assign_place(array_access.array);
141	                self.get_array_member(identifier.name, &array_access.index).expect("We have visited all array writes.")
142	            }
143	            Path(path) => leo_ast::Identifier { name: path.identifier().name, span: path.span, id: path.id },
144	            MemberAccess(member_access) => {
145	                let identifier = self.reconstruct_assign_place(member_access.inner);
146	                self.get_composite_member(identifier.name, member_access.name.name)
147	                    .expect("We have visited all composites writes.")
148	            }
149	            TupleAccess(_) => panic!("TupleAccess writes should have been removed by Destructuring"),
150	            _ => panic!("Type checking should have ensured there are no other places for assignments"),
151	        }
152	    }
153	
154	    /// If we're assigning to a composite or array, create assignments to the individual members, if applicable.
155	    pub fn reconstruct_assign_recurse(&self, place: Identifier, value: Expression, accumulate: &mut Vec<Statement>) {
156	        if let Some(array_members) = self.array_members.get(&place.name) {
157	            if let Expression::Array(value_array) = value {
158	                // This was an assignment like
159	                // `arr = [a, b, c];`
160	                // Change it to this:
161	                // `arr_0 = a; arr_1 = b; arr_2 = c`
162	                for (&member, rhs_element) in array_members.iter().zip(value_array.elements) {
163	                    self.reconstruct_assign_recurse(member, rhs_element, accumulate);
164	                }
165	            } else {
166	                // This was an assignment like
167	                // `arr = x;`
168	                // Change it to this:
169	                // `arr = x; arr_0 = x[0]; arr_1 = x[1]; arr_2 = x[2];`
170	                let one_assign = AssignStatement {
171	                    place: Path::from(place).to_local().into(),
172	                    value,
173	                    span: Default::default(),
174	                    id: self.state.node_builder.next_id(),
175	                }
176	                .into();
177	                accumulate.push(one_assign);
178	                for (i, &member) in array_members.iter().enumerate() {
179	                    let access = ArrayAccess {
180	                        array: Path::from(place).to_local().into(),
181	                        index: Literal::integer(
182	                            IntegerType::U32,
183	                            format!("{i}u32"),
184	                            Default::default(),
185	                            self.state.node_builder.next_id(),
186	                        )
187	                        .into(),
188	                        span: Default::default(),
189	                        id: self.state.node_builder.next_id(),
190	                    };
191	                    self.reconstruct_assign_recurse(member, access.into(), accumulate);
192	                }
193	            }
194	        } else if let Some(composite_members) = self.composite_members.get(&place.name) {
195	            if let Expression::Composite(value_composite) = value {
196	                // This was an assignment like
197	                // `struc = S { field0: a, field1: b };`
198	                // Change it to this:
199	                // `struc_field0 = a; struc_field1 = b;`
200	                for initializer in value_composite.members.into_iter() {
201	                    let member_name =
202	                        composite_members.get(&initializer.identifier.name).expect("Member should exist.");
203	                    let rhs_expression =
204	                        initializer.expression.expect("This should have been normalized to have a value.");
205	                    self.reconstruct_assign_recurse(*member_name, rhs_expression, accumulate);
206	                }
207	            } else {
208	                // This was an assignment like
209	                // `struc = x;`
210	                // Change it to this:
211	                // `struc = x; struc_field0 = x.field0; struc_field1 = x.field1;`
212	                let one_assign = AssignStatement {
213	                    place: Path::from(place).to_local().into(),
214	                    value,
215	                    span: Default::default(),
216	                    id: self.state.node_builder.next_id(),
217	                }
218	                .into();
219	                accumulate.push(one_assign);
220	                for (field, member_name) in composite_members.iter() {
221	                    let access = MemberAccess {
222	                        inner: Path::from(place).to_local().into(),
223	                        name: Identifier::new(*field, self.state.node_builder.next_id()),
224	                        span: Default::default(),
225	                        id: self.state.node_builder.next_id(),
226	                    };
227	                    if let Some(member_type) = self.state.type_table.get(&member_name.id) {
228	                        self.state.type_table.insert(access.id, member_type);
229	                    }
230	                    self.reconstruct_assign_recurse(*member_name, access.into(), accumulate);
231	                }
232	            }
233	        } else {
234	            let stmt = AssignStatement {
235	                value,
236	                place: Path::from(place).to_local().into(),
237	                id: self.state.node_builder.next_id(),
238	                span: Default::default(),
239	            }
240	            .into();
241	            accumulate.push(stmt);
242	        }
243	    }
244	}
245	
246	struct WriteTransformingFiller<'a>(WriteTransformingVisitor<'a>);
247	
248	impl AstVisitor for WriteTransformingFiller<'_> {
249	    type AdditionalInput = ();
250	    type Output = ();
251	
252	    /* Expressions */
253	    fn visit_expression(&mut self, _input: &Expression, _additional: &Self::AdditionalInput) -> Self::Output {}
254	
255	    /* Statements */
256	    fn visit_assign(&mut self, input: &AssignStatement) {
257	        self.access_recurse(&input.place);
258	    }
259	}

