16	use crate::CompilerState;
17	
18	use leo_ast::{Expression, Location, Node, NodeID, const_eval::Value};
19	use leo_errors::StaticAnalyzerError;
20	use leo_span::{Span, Symbol};
21	
22	use indexmap::IndexMap;
23	
24	/// Visitor that propagates constant values through the program.
25	pub struct SsaConstPropagationVisitor<'a> {
26	    pub state: &'a mut CompilerState,
27	    /// Current program being analyzed.
28	    pub program: Symbol,
29	    /// Maps variable names to their constant values.
30	    /// Only variables assigned constant values are tracked here.
31	    pub constants: IndexMap<Symbol, Value>,
32	    /// Have we actually modified the program at all?
33	    pub changed: bool,
34	}
35	
36	impl SsaConstPropagationVisitor<'_> {
37	    /// Emit a `StaticAnalyzerError`.
38	    pub fn emit_err(&self, err: StaticAnalyzerError) {
39	        self.state.handler.emit_err(err);
40	    }
41	
42	    /// Convert a Value to an Expression.
43	    /// Returns the new expression and its node ID.
44	    /// If the original node doesn't have a type, this will return None.
45	    pub fn value_to_expression(&mut self, value: &Value, span: Span, id: NodeID) -> Option<(Expression, NodeID)> {
46	        let ty = self.state.type_table.get(&id)?.clone();
47	        let symbol_table = &self.state.symbol_table;
48	        let struct_lookup = |loc: &Location| {
49	            symbol_table
50	                .lookup_struct(self.program, loc)
51	                .unwrap()
52	                .members
53	                .iter()
54	                .map(|mem| (mem.identifier.name, mem.type_.clone()))
55	                .collect()
56	        };
57	        let new_expr = value.to_expression(span, &self.state.node_builder, &ty, &struct_lookup)?;
58	        let new_id = new_expr.id();
59	
60	        // Copy the type information to the new node ID.
61	        self.copy_types_recursively(&new_expr, &ty);
62	
63	        Some((new_expr, new_id))
64	    }
65	
66	    /// Copy types for nested expressions based on the type structure.
67	    /// This ensures that ALL expressions in the tree have proper type information.
68	    fn copy_types_recursively(&mut self, expr: &Expression, ty: &leo_ast::Type) {
69	        use leo_ast::Type;
70	
71	        self.state.type_table.insert(expr.id(), ty.clone());
72	
73	        // Then recursively handle nested expressions
74	        match (expr, ty) {
75	            (Expression::Array(array_expr), Type::Array(array_ty)) => {
76	                for element in &array_expr.elements {
77	                    self.copy_types_recursively(element, array_ty.element_type());
78	                }
79	            }
80	            (Expression::Tuple(tuple_expr), Type::Tuple(tuple_ty)) => {
81	                for (element, elem_ty) in tuple_expr.elements.iter().zip(tuple_ty.elements()) {
82	                    self.copy_types_recursively(element, elem_ty);
83	                }
84	            }
85	            (Expression::Composite(composite_expr), Type::Composite(composite_ty)) => {
86	                // We only look for structs here (not records) because `copy_types_recursively` is
87	                // only called from `value_to_expression`, which never produces record expressions.
88	                let member_types: Vec<leo_ast::Type> = self
89	                    .state
90	                    .symbol_table
